from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Callable, List, Dict, Any, Optional
import time
import random

@dataclass
class RetryConfig:
    max_attempts: int = 3
    initial_delay: float = 1.0
    max_delay: float = 30.0
    exponential_base: float = 2.0
    jitter: bool = True
    jitter_range: float = 0.3

@dataclass
class RetryMetrics:
    total_attempts: int = 0
    successful_retries: int = 0
    failed_operations: int = 0
    total_delay_time: float = 0.0
    errors_by_type: Dict[str, int] = field(default_factory=dict)

class RetryStrategy(ABC):
    def __init__(self, config: RetryConfig):
        self.config = config

    @abstractmethod
    def calculate_delay(self, attempt: int) -> float:
        pass

    @abstractmethod
    def should_retry(self, attempt: int, error: Exception) -> bool:
        pass

class ExponentialBackoffStrategy(RetryStrategy):
    def calculate_delay(self, attempt: int) -> float:
        base_delay = self.config.initial_delay * (self.config.exponential_base ** attempt)
        delay = min(base_delay, self.config.max_delay)

        if self.config.jitter:
            jitter_amount = delay * self.config.jitter_range
            delay += random.uniform(-jitter_amount, jitter_amount)

        return max(0, delay)

    def should_retry(self, attempt: int, error: Exception) -> bool:
        if attempt >= self.config.max_attempts:
            return False
        retryable = getattr(error, 'retryable', True)
        return retryable

class LinearBackoffStrategy(RetryStrategy):
    def calculate_delay(self, attempt: int) -> float:
        delay = self.config.initial_delay * (attempt + 1)
        delay = min(delay, self.config.max_delay)

        if self.config.jitter:
            jitter_amount = delay * 0.2
            delay += random.uniform(-jitter_amount, jitter_amount)

        return max(0, delay)

    def should_retry(self, attempt: int, error: Exception) -> bool:
        if attempt >= self.config.max_attempts:
            return False
        return getattr(error, 'retryable', True)

class RetryExecutor:
    def __init__(self, strategy: RetryStrategy):
        self.strategy = strategy
        self.metrics = RetryMetrics()
        self.callbacks: List[Callable] = []

    def add_callback(self, callback: Callable[[int, Exception, float], None]):
        self.callbacks.append(callback)

    def _notify_callbacks(self, attempt: int, error: Exception, delay: float):
        for callback in self.callbacks:
            try:
                callback(attempt, error, delay)
            except Exception:
                pass

    def execute(self, operation: Callable, *args, **kwargs) -> Any:
        last_error = None

        for attempt in range(self.strategy.config.max_attempts):
            self.metrics.total_attempts += 1

            try:
                result = operation(*args, **kwargs)
                if attempt > 0:
                    self.metrics.successful_retries += 1
                return result

            except Exception as e:
                last_error = e
                error_type = type(e).__name__
                self.metrics.errors_by_type[error_type] = \
                    self.metrics.errors_by_type.get(error_type, 0) + 1

                if not self.strategy.should_retry(attempt, e):
                    break

                if attempt < self.strategy.config.max_attempts - 1:
                    delay = self.strategy.calculate_delay(attempt)
                    self.metrics.total_delay_time += delay
                    self._notify_callbacks(attempt, e, delay)
                    time.sleep(delay)

        self.metrics.failed_operations += 1
        raise last_error

from dataclasses import dataclass, field
from typing import List, Dict, Any
from enum import Enum
import time

class DegradationMode(Enum):
    FULL = "full"
    REDUCED = "reduced"
    FALLBACK = "fallback"
    MINIMAL = "minimal"

@dataclass
class HealthMetrics:
    quantum_availability: float = 1.0
    error_rate: float = 0.0
    latency_factor: float = 1.0
    queue_depth: int = 0

@dataclass
class DegradationLevel:
    mode: DegradationMode
    capabilities: List[str]
    performance_factor: float
    health_threshold: float

class GracefulDegradationManager:
    def __init__(self):
        self.current_mode = DegradationMode.FULL
        self.health = HealthMetrics()
        self.transition_history: List[Dict] = []
        self.levels = self._define_levels()

    def _define_levels(self) -> Dict[DegradationMode, DegradationLevel]:
        return {
            DegradationMode.FULL: DegradationLevel(
                mode=DegradationMode.FULL,
                capabilities=["vqe", "qaoa", "grover", "qml", "error_mitigation", "advanced_circuits"],
                performance_factor=1.0,
                health_threshold=0.8
            ),
            DegradationMode.REDUCED: DegradationLevel(
                mode=DegradationMode.REDUCED,
                capabilities=["vqe", "qaoa", "basic_circuits"],
                performance_factor=0.7,
                health_threshold=0.5
            ),
            DegradationMode.FALLBACK: DegradationLevel(
                mode=DegradationMode.FALLBACK,
                capabilities=["basic_circuits", "classical_vqe"],
                performance_factor=0.4,
                health_threshold=0.2
            ),
            DegradationMode.MINIMAL: DegradationLevel(
                mode=DegradationMode.MINIMAL,
                capabilities=["status_check", "cached_results"],
                performance_factor=0.1,
                health_threshold=0.0
            )
        }

    def update_metrics(self, **kwargs):
        for key, value in kwargs.items():
            if hasattr(self.health, key):
                setattr(self.health, key, value)
        self._evaluate_mode()

    def _calculate_health_score(self) -> float:
        availability_weight = 0.4
        error_weight = 0.3
        latency_weight = 0.2
        queue_weight = 0.1

        latency_score = 1.0 / max(self.health.latency_factor, 0.1)
        queue_score = max(0, 1.0 - self.health.queue_depth / 100)

        score = (
            self.health.quantum_availability * availability_weight +
            (1 - self.health.error_rate) * error_weight +
            latency_score * latency_weight +
            queue_score * queue_weight
        )
        return max(0.0, min(1.0, score))

    def _evaluate_mode(self):
        health_score = self._calculate_health_score()

        mode_order = [
            DegradationMode.FULL,
            DegradationMode.REDUCED,
            DegradationMode.FALLBACK,
            DegradationMode.MINIMAL
        ]

        target_mode = DegradationMode.MINIMAL
        for mode in mode_order:
            if health_score >= self.levels[mode].health_threshold:
                target_mode = mode
                break

        if target_mode != self.current_mode:
            self._transition_to(target_mode)

    def _transition_to(self, new_mode: DegradationMode):
        self.transition_history.append({
            "from": self.current_mode.value,
            "to": new_mode.value,
            "timestamp": time.time(),
            "health_score": self._calculate_health_score(),
            "metrics": {
                "availability": self.health.quantum_availability,
                "error_rate": self.health.error_rate,
                "latency": self.health.latency_factor
            }
        })
        self.current_mode = new_mode

    def can_execute(self, capability: str) -> bool:
        return capability in self.levels[self.current_mode].capabilities

    def get_performance_factor(self) -> float:
        return self.levels[self.current_mode].performance_factor

