from abc import ABC, abstractmethod
from typing import Dict, Any, Optional, List
from dataclasses import dataclass
import numpy as np
from scipy.optimize import minimize

@dataclass
class FallbackInfo:
    implementation: Any
    accuracy_estimate: float
    max_problem_size: int
    description: str

class FallbackStrategy(ABC):
    @abstractmethod
    def execute(self, *args, **kwargs) -> Dict[str, Any]:
        pass

    @abstractmethod
    def estimate_quality(self, problem_size: int) -> float:
        pass

    @abstractmethod
    def can_handle(self, problem_size: int) -> bool:
        pass

class VQEFallback(FallbackStrategy):
    def __init__(self, max_qubits: int = 20):
        self.max_qubits = max_qubits

    def execute(
        self,
        hamiltonian: np.ndarray,
        initial_params: np.ndarray = None
    ) -> Dict[str, Any]:
        dim = hamiltonian.shape[0]
        num_qubits = int(np.log2(dim))

        if num_qubits <= 10:
            eigenvalues, eigenvectors = np.linalg.eigh(hamiltonian)
            return {
                "ground_energy": float(eigenvalues[0]),
                "ground_state": eigenvectors[:, 0].tolist(),
                "method": "exact_diagonalization",
                "quality": 1.0
            }

        if initial_params is None:
            initial_params = np.random.uniform(0, 2*np.pi, num_qubits * 2)

        def cost_fn(params):
            state = np.zeros(dim, dtype=complex)
            state[0] = 1.0
            for i, p in enumerate(params[:dim]):
                state[i % dim] *= np.exp(1j * p)
            state = state / np.linalg.norm(state)
            return np.real(state.conj() @ hamiltonian @ state)

        result = minimize(cost_fn, initial_params, method='COBYLA')

        return {
            "ground_energy": float(result.fun),
            "optimal_params": result.x.tolist(),
            "method": "classical_variational",
            "quality": 0.85,
            "iterations": result.nfev
        }

    def estimate_quality(self, problem_size: int) -> float:
        if problem_size <= 10:
            return 1.0
        elif problem_size <= 15:
            return 0.9
        else:
            return max(0.7, 1.0 - (problem_size - 15) * 0.02)

    def can_handle(self, problem_size: int) -> bool:
        return problem_size <= self.max_qubits

class SamplingFallback(FallbackStrategy):
    def __init__(self, max_samples: int = 100000):
        self.max_samples = max_samples

    def execute(
        self,
        distribution: np.ndarray,
        num_samples: int
    ) -> Dict[str, Any]:
        probs = distribution / distribution.sum()
        num_samples = min(num_samples, self.max_samples)

        samples = np.random.choice(len(probs), size=num_samples, p=probs)
        unique, counts = np.unique(samples, return_counts=True)

        n_bits = int(np.ceil(np.log2(len(probs))))
        result_counts = {
            format(u, f'0{n_bits}b'): int(c)
            for u, c in zip(unique, counts)
        }

        return {
            "counts": result_counts,
            "num_samples": num_samples,
            "method": "monte_carlo",
            "quality": 0.95
        }

    def estimate_quality(self, problem_size: int) -> float:
        return 0.95

    def can_handle(self, problem_size: int) -> bool:
        return 2 ** problem_size <= self.max_samples * 10

class FallbackRegistry:
    def __init__(self):
        self.fallbacks: Dict[str, FallbackInfo] = {}

    def register(
        self,
        name: str,
        strategy: FallbackStrategy,
        accuracy: float,
        max_size: int,
        description: str
    ):
        self.fallbacks[name] = FallbackInfo(
            implementation=strategy,
            accuracy_estimate=accuracy,
            max_problem_size=max_size,
            description=description
        )

    def get_fallback(
        self,
        name: str,
        problem_size: int = None,
        min_accuracy: float = 0.0
    ) -> Optional[FallbackStrategy]:
        if name not in self.fallbacks:
            return None

        info = self.fallbacks[name]

        if problem_size and not info.implementation.can_handle(problem_size):
            return None

        if info.accuracy_estimate < min_accuracy:
            return None

        return info.implementation

    def list_available(self, problem_size: int) -> List[str]:
        available = []
        for name, info in self.fallbacks.items():
            if info.implementation.can_handle(problem_size):
                available.append(name)
        return available

from typing import Callable, Dict, Any, Optional, List
from dataclasses import dataclass, field
import time

@dataclass
class ExecutionResult:
    success: bool
    result: Any
    execution_type: str
    attempts: int
    total_time: float
    errors: List[Dict] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)

class ResilientQuantumExecutor:
    def __init__(
        self,
        retry_strategy,
        degradation_manager,
        fallback_registry
    ):
        self.retry_executor = RetryExecutor(retry_strategy)
        self.degradation = degradation_manager
        self.fallbacks = fallback_registry
        self.execution_history: List[ExecutionResult] = []

    def execute_with_resilience(
        self,
        operation_name: str,
        quantum_fn: Callable,
        fallback_name: str = None,
        *args,
        **kwargs
    ) -> ExecutionResult:
        start_time = time.time()
        errors = []

        result = ExecutionResult(
            success=False,
            result=None,
            execution_type="none",
            attempts=0,
            total_time=0.0,
            metadata={
                "operation": operation_name,
                "degradation_mode": self.degradation.current_mode.value
            }
        )

        if self.degradation.can_execute(operation_name):
            quantum_success, quantum_result, quantum_errors, attempts = \
                self._try_quantum(quantum_fn, *args, **kwargs)

            result.attempts = attempts
            errors.extend(quantum_errors)

            if quantum_success:
                result.success = True
                result.result = quantum_result
                result.execution_type = "quantum"
                self._update_degradation(True)
            else:
                self._update_degradation(False, quantum_errors[-1].get("type") if quantum_errors else None)
        else:
            errors.append({
                "type": "capability_unavailable",
                "message": f"'{operation_name}' not available in current mode"
            })

        if not result.success and fallback_name:
            fallback_success, fallback_result, fallback_errors = \
                self._try_fallback(fallback_name, *args, **kwargs)

            errors.extend(fallback_errors)

            if fallback_success:
                result.success = True
                result.result = fallback_result
                result.execution_type = "fallback"
                result.metadata["fallback_used"] = fallback_name

        result.errors = errors
        result.total_time = time.time() - start_time

        self.execution_history.append(result)
        return result

    def _try_quantum(
        self,
        quantum_fn: Callable,
        *args,
        **kwargs
    ) -> tuple:
        errors = []
        attempts = 0

        try:
            result = self.retry_executor.execute(quantum_fn, *args, **kwargs)
            attempts = self.retry_executor.metrics.total_attempts
            return True, result, errors, attempts
        except Exception as e:
            errors.append({
                "type": type(e).__name__,
                "message": str(e),
                "timestamp": time.time()
            })
            attempts = self.retry_executor.metrics.total_attempts
            return False, None, errors, attempts

    def _try_fallback(
        self,
        fallback_name: str,
        *args,
        **kwargs
    ) -> tuple:
        errors = []

        fallback = self.fallbacks.get_fallback(fallback_name)
        if fallback is None:
            errors.append({
                "type": "fallback_not_found",
                "message": f"No fallback '{fallback_name}' registered"
            })
            return False, None, errors

        try:
            result = fallback.execute(*args, **kwargs)
            return True, result, errors
        except Exception as e:
            errors.append({
                "type": f"fallback_{type(e).__name__}",
                "message": str(e)
            })
            return False, None, errors

    def _update_degradation(self, success: bool, error_type: str = None):
        current = self.degradation.health

        if success:
            self.degradation.update_metrics(
                error_rate=max(0, current.error_rate - 0.05)
            )
        else:
            self.degradation.update_metrics(
                error_rate=min(1.0, current.error_rate + 0.15)
            )

            if error_type and "hardware" in error_type.lower():
                self.degradation.update_metrics(
                    quantum_availability=current.quantum_availability * 0.7
                )

    def get_execution_report(self) -> Dict[str, Any]:
        if not self.execution_history:
            return {"total_executions": 0}

        quantum_count = sum(1 for e in self.execution_history if e.execution_type == "quantum")
        fallback_count = sum(1 for e in self.execution_history if e.execution_type == "fallback")
        success_count = sum(1 for e in self.execution_history if e.success)

        return {
            "total_executions": len(self.execution_history),
            "success_rate": success_count / len(self.execution_history),
            "quantum_executions": quantum_count,
            "fallback_executions": fallback_count,
            "average_time": sum(e.total_time for e in self.execution_history) / len(self.execution_history),
            "average_attempts": sum(e.attempts for e in self.execution_history) / len(self.execution_history),
            "current_degradation_mode": self.degradation.current_mode.value,
            "retry_metrics": self.retry_executor.metrics.__dict__
        }
